import http from 'k6/http';
import { check, group, sleep } from 'k6';
import { Rate, Trend } from 'k6/metrics';
import { loginAndGetToken } from '../../tests/k6/helpers/auth.js';

const errorRate = new Rate('errors');
const ingredientAnalyticsDuration = new Trend('ingredient_analytics_duration');
const ratingAnalyticsDuration = new Trend('rating_analytics_duration');

const BASE_URL = __ENV.BASE_URL || 'https://quickpizza.grafana.com';

// Varied query parameters for realistic access patterns
const PERIODS = ['7d', '30d', '90d'];
const LIMITS = [5, 10, 25, 50];

export const options = {
  scenarios: {
    smoke: {
      executor: 'per-vu-iterations',
      vus: 1,
      iterations: 5,
      maxDuration: '30s',
      exec: 'smokeTest',
      startTime: '0s',
    },
    load_test: {
      executor: 'constant-arrival-rate',
      rate: 15,
      timeUnit: '1s',
      duration: '2m',
      preAllocatedVUs: 25,
      maxVUs: 50,
      exec: 'default',
      startTime: '35s',
      gracefulStop: '30s',
    },
    baseline_regression: {
      executor: 'constant-vus',
      vus: 5,
      duration: '30s',
      exec: 'baselineTest',
      startTime: '3m10s',
    },
  },
  thresholds: {
    http_req_failed: ['rate<0.01'],
    http_req_duration: ['p(95)<3000'],
    'http_req_duration{endpoint:/api/analytics/ingredients}': ['p(95)<3000'],
    'http_req_duration{endpoint:/api/analytics/ratings}': ['p(95)<3000'],
    'http_req_duration{endpoint:/api/ratings}': ['p(95)<2000'],
    errors: ['rate<0.05'],
  },
};

export function setup() {
  const token = loginAndGetToken();
  return { token: token };
}

export function smokeTest(data) {
  group('Smoke: Ingredient Analytics', function () {
    const res = http.get(`${BASE_URL}/api/analytics/ingredients?limit=10&period=30d`, {
      headers: { 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/analytics/ingredients', type: 'read', scenario: 'smoke' },
    });
    check(res, {
      'status is 200 or 404': (r) => r.status === 200 || r.status === 404,
      'response time < 5s': (r) => r.timings.duration < 5000,
    });
  });

  group('Smoke: Rating Analytics', function () {
    const res = http.get(`${BASE_URL}/api/analytics/ratings?period=30d&top=5`, {
      headers: { 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/analytics/ratings', type: 'read', scenario: 'smoke' },
    });
    check(res, {
      'status is 200 or 404': (r) => r.status === 200 || r.status === 404,
      'response time < 5s': (r) => r.timings.duration < 5000,
    });
  });
}

export default function (data) {
  const period = PERIODS[Math.floor(Math.random() * PERIODS.length)];
  const limit = LIMITS[Math.floor(Math.random() * LIMITS.length)];

  group('Ingredient Analytics — varied query params', function () {
    const res = http.get(
      `${BASE_URL}/api/analytics/ingredients?limit=${limit}&period=${period}`,
      {
        headers: { 'Authorization': `Bearer ${data.token}` },
        tags: { endpoint: '/api/analytics/ingredients', type: 'read', scenario: 'load_test' },
      }
    );

    const success = check(res, {
      'status is 200 or 404': (r) => r.status === 200 || r.status === 404,
      'response time < 3s': (r) => r.timings.duration < 3000,
      'valid JSON': (r) => {
        try { JSON.parse(r.body); return true; } catch { return false; }
      },
    });

    errorRate.add(!success);
    ingredientAnalyticsDuration.add(res.timings.duration);
  });

  group('Rating Analytics — varied query params', function () {
    const topN = Math.floor(Math.random() * 10) + 1;
    const res = http.get(
      `${BASE_URL}/api/analytics/ratings?period=${period}&top=${topN}`,
      {
        headers: { 'Authorization': `Bearer ${data.token}` },
        tags: { endpoint: '/api/analytics/ratings', type: 'read', scenario: 'load_test' },
      }
    );

    const success = check(res, {
      'status is 200 or 404': (r) => r.status === 200 || r.status === 404,
      'response time < 3s': (r) => r.timings.duration < 3000,
      'valid JSON': (r) => {
        try { JSON.parse(r.body); return true; } catch { return false; }
      },
    });

    errorRate.add(!success);
    ratingAnalyticsDuration.add(res.timings.duration);
  });

  sleep(0.5);
}

export function baselineTest(data) {
  group('Baseline Regression', function () {
    const ratingsRes = http.get(`${BASE_URL}/api/ratings`, {
      headers: { 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/ratings', scenario: 'baseline' },
    });
    check(ratingsRes, {
      'ratings 200': (r) => r.status === 200,
      'has ratings': (r) => {
        try { return JSON.parse(r.body).ratings !== undefined; } catch { return false; }
      },
    });

    const pizzaRes = http.post(`${BASE_URL}/api/pizza`, JSON.stringify({}), {
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${data.token}` },
      tags: { endpoint: '/api/pizza', scenario: 'baseline' },
    });
    check(pizzaRes, {
      'pizza 200': (r) => r.status === 200,
    });
  });
  sleep(0.5);
}

export function handleSummary(data) {
  return {
    stdout: JSON.stringify(data, null, 2),
    'summary.json': JSON.stringify(data),
  };
}
